  ('customs-f19eb2bd-moex-00112', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '船舶於靜水狀態下行進，在固定轉速下持續將船舵轉至滿舵時，其迴轉圈（Turningcircle）為最小，其過', '["偏移", "船速降低", "船體下沉", "傾斜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "b14ecfcba47e", "answer_pdf_sha1": "7eb32a391986", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
